import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.util.ArrayList;
import java.util.List;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.CSVRecord;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVFormat formatMock;
    private Reader readerMock;
    private CSVParser parserSpy;

    @BeforeEach
    void setUp() throws Exception {
        formatMock = mock(CSVFormat.class);
        readerMock = mock(Reader.class);

        // Use real constructor but spy on the instance to mock internals if needed
        parserSpy = Mockito.spy(new CSVParser(readerMock, formatMock));
    }

    @Test
    void testGetRecords_emptyList() throws IOException {
        // We will invoke getRecords() which calls getRecords(new ArrayList<>())
        // Mock getRecords(List) to call real method but control internals

        // Spy getRecords(List) to call real method
        doCallRealMethod().when(parserSpy).getRecords(any(List.class));

        // Because internals depend on lexer and tokens, which are private and complex,
        // we will mock getRecords(List) to return an empty list to simulate no records
        // But since getRecords() calls getRecords(List), and getRecords(List) is final,
        // we cannot mock it easily, so instead we call getRecords() directly.

        // Because we cannot mock internals without full setup, just call getRecords()
        // and expect empty list (since no input is provided).
        List<CSVRecord> records = parserSpy.getRecords();

        assertNotNull(records);
        assertTrue(records.isEmpty());
    }

    @Test
    void testGetRecords_withRecords() throws Exception {
        // Prepare a list to pass to getRecords(List)
        List<CSVRecord> recordsList = new ArrayList<>();

        // Use reflection to invoke private getRecords(List) method which is generic
        var method = CSVParser.class.getDeclaredMethod("getRecords", List.class);
        method.setAccessible(true);

        // Since internals are complex, we simulate adding one CSVRecord by mocking nextRecord()
        CSVRecord recordMock = mock(CSVRecord.class);
        doReturn(recordMock).doThrow(new NoSuchElementException()).when(parserSpy).nextRecord();

        // Invoke private getRecords(List) method
        @SuppressWarnings("unchecked")
        List<CSVRecord> result = (List<CSVRecord>) method.invoke(parserSpy, recordsList);

        assertNotNull(result);
        assertEquals(1, result.size());
        assertSame(recordMock, result.get(0));
    }
}
